const body = $input.first().json.body || $input.first().json;
const novedades = Array.isArray(body.novedades) ? body.novedades : [];
if (novedades.length === 0) throw new Error('novedades array is required');
return novedades.map(b => ({ json: {
  id:              b.id || '',
  period_id:       b.period_id || body.period_id || '',
  employee_id:     b.employee_id || '',
  novedad_type:    b.novedad_type || 'licencia_ordinaria',
  start_date:      b.start_date || '',
  end_date:        b.end_date || '',
  days_count:      b.days_count != null ? String(b.days_count) : '',
  hours_count:     b.hours_count != null ? String(b.hours_count) : '',
  amount_override: b.amount_override != null ? String(b.amount_override) : '',
  notes:           b.notes || '',
  created_by:      body.created_by || ''
} }));
